import { AnnotationsTooltipHandler } from './types/annotations-tooltip-props.js';
import { prepareCustomTooltipData } from './utils/prepare-custom-tooltip-data.js';
import { annotationsGroupsScrollContainer } from '../../../overlay-tooltip/tooltip.sty.js';
import { useAnnotationsSelectionState } from '../../hooks/store/selectors.js';
import { AnnotationsMarkerGroup } from '../../types/annotations.js';

interface AnnotationsCustomizedTooltipProps {
  data: AnnotationsMarkerGroup[];
  tooltipTemplate: AnnotationsTooltipHandler;
}

export const AnnotationsCustomizedTooltip = ({
  data,
  tooltipTemplate,
}: AnnotationsCustomizedTooltipProps) => {
  const { hoveredItem } = useAnnotationsSelectionState();
  const parsedData = prepareCustomTooltipData(data, hoveredItem ?? '');

  return (
    <div className={annotationsGroupsScrollContainer}>
      {tooltipTemplate(parsedData.hoveredMarkers, parsedData.closeMarkers)}
    </div>
  );
};

AnnotationsCustomizedTooltip['displayName'] = 'AnnotationsCustomizedTooltip';
